import { OrderBuilder } from '@uniswap/uniswapx-sdk';
const order = new OrderBuilder()
  .input({ token: WETH, startAmount: parseEther('100'), endAmount: parseEther('100') })
  .output({ token: USDC, startAmount: parseUnits('310000', 6), endAmount: parseUnits('308000', 6) })
  .deadline(deadline)
  .build();
const sig = await account.signTypedData(order.permitData());
await fetch('https://api.uniswap.org/v2/orders', { method: 'POST', body: JSON.stringify({ order, sig }) });
